// ── Đọc payload từ BE ──
const rawInput = $input.first().json.body ?? $input.first().json;
const body = typeof rawInput === 'string' ? JSON.parse(rawInput) : rawInput;

const endpoints = body.endpoints;
if (!Array.isArray(endpoints) || endpoints.length === 0) {
  throw new Error('Payload thiếu mảng endpoints hoặc rỗng.');
}

const callbackUrl = body.callbackUrl ?? '';
const callbackApiKey = body.callbackApiKey ?? '';
const globalBusinessRules = body.globalBusinessRules ?? '';
const endpointBusinessContexts = body.endpointBusinessContexts ?? {};
const testSuiteId = body.testSuiteId ?? '';

return [{
  json: {
    endpoints,
    callbackUrl,
    callbackApiKey,
    globalBusinessRules,
    endpointBusinessContexts,
    testSuiteId
  }
}];

const { endpoints, globalBusinessRules, endpointBusinessContexts } = $input.first().json;

// ── Xây dựng mô tả từng endpoint ──
const epLines = endpoints.map((ep, i) => {
  const ctx = endpointBusinessContexts?.[ep.endpointId]
    ? `\n   Business context: ${endpointBusinessContexts[ep.endpointId]}`
    : '';
  const deps = ep.dependsOnEndpointIds?.length > 0
    ? `\n   DependsOn: [${ep.dependsOnEndpointIds.join(', ')}]` : '';
  const auth = ep.isAuthRelated ? ' [AUTH-RELATED]' : '';
  return `${i + 1}. [ID=${ep.endpointId}] ${ep.httpMethod} ${ep.path}${auth}${deps}${ctx}`;
}).join('\n');

const rulesSection = globalBusinessRules
  ? `\n\n=== GLOBAL BUSINESS RULES ===\n${globalBusinessRules}` : '';

// ── System prompt ──
const systemPrompt = `You are a senior QA engineer specialising in REST API automated testing.
Your task: generate comprehensive, executable test cases for a set of REST API endpoints.
Focus on correctness, coverage, and realistic test data.`;

// ── User prompt ──
const userPrompt = `Generate test cases for the following ordered REST API endpoints.${rulesSection}

=== ENDPOINTS ===
${epLines}

=== TEST CASE GENERATION RULES ===
1. Generate at least one HappyPath test per endpoint.
2. Generate at least one Negative test per endpoint (invalid input, missing required fields, wrong auth, etc.).
3. [AUTH-RELATED] endpoints: generate a test for missing/invalid token returning 401.
4. Use realistic but clearly synthetic test data (e.g. username: "testuser_gen", email: "qa_test@example.com").
5. For endpoints that CREATE resources, set expectedStatus to "[201]" or "[200]" as appropriate.
6. For endpoints that READ resources, set expectedStatus to "[200]".
7. For endpoints that DELETE resources, set expectedStatus to "[200]" or "[204]".
8. Negative tests should expect "[400]" or "[401]" or "[403]" or "[404]" as appropriate.
9. Body must be a JSON string (serialized JSON), or null if the endpoint has no body.
10. The url field should be the endpoint path, e.g. "/api/users" or "/api/users/{id}" with a realistic placeholder value.

=== RESPONSE FORMAT ===
Respond with ONLY a raw JSON object. No markdown, no code fences, no explanation outside JSON.

{
  "testCases": [
    {
      "endpointId": "<exact UUID from input>",
      "name": "<short descriptive name, e.g. 'POST /api/users - HappyPath: Create valid user'>",
      "description": "<one sentence describing what this test validates>",
      "testType": "<HappyPath | Boundary | Negative | Performance | Security>",
      "priority": "<Critical | High | Medium | Low>",
      "orderIndex": <0-based integer matching execution order>,
      "tags": null,
      "request": {
        "httpMethod": "<GET|POST|PUT|DELETE|PATCH>",
        "url": "<endpoint path with realistic path param values if needed>",
        "headers": null,
        "pathParams": null,
        "queryParams": null,
        "bodyType": "<None|JSON|FormData|UrlEncoded|Raw>",
        "body": "<serialized JSON string or null>",
        "timeout": 30000
      },
      "expectation": {
        "expectedStatus": "<JSON array string e.g. \"[200]\" or \"[201]\" or \"[400]\">",
        "responseSchema": null,
        "headerChecks": null,
        "bodyContains": null,
        "bodyNotContains": null,
        "jsonPathChecks": null,
        "maxResponseTime": null
      }
    }
  ]
}

IMPORTANT: orderIndex must be unique 0-based integers. Assign them so that HappyPath tests for a resource run before Negative tests for the same resource.`;

const openAiBody = {
  model: 'gpt-4o',
  temperature: 0.2,
  max_tokens: 8192,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{
  json: {
    openAiBody,
    userPrompt,
    systemPrompt,
    originalInput: $input.first().json
  }
}];

// ── Đọc response (hỗ trợ cả AI Agent lẫn HTTP Request tới OpenAI) ──
const response = $input.first().json;

if (response.error) {
  throw new Error(`OpenAI API error: ${response.error.message ?? JSON.stringify(response.error)}`);
}

// AI Agent node trả về { output: '...' }
// HTTP Request node trả về { choices: [{message:{content:'...'}}] }
const rawContent = response.output
  ?? response.choices?.[0]?.message?.content
  ?? null;

if (!rawContent) {
  throw new Error('LLM trả về response rỗng hoặc không đúng format. Keys: ' + Object.keys(response).join(', '));
}

// ── Loại bỏ markdown code block nếu có ──
let cleaned = rawContent.trim();
if (cleaned.startsWith('```')) {
  cleaned = cleaned.replace(/^```(?:json)?\s*\n?/, '').replace(/\n?```\s*$/, '').trim();
}

// ── Parse JSON ──
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Không parse được JSON từ LLM. Error: ${e.message}\nRaw (500 chars): ${cleaned.substring(0, 500)}`);
}

const testCases = parsed.testCases;
if (!Array.isArray(testCases) || testCases.length === 0) {
  throw new Error('LLM response thiếu mảng testCases hoặc rỗng.');
}

// ── Chuẩn hóa orderIndex ──
testCases.sort((a, b) => (a.orderIndex ?? 0) - (b.orderIndex ?? 0));
testCases.forEach((tc, i) => { tc.orderIndex = i; });

// ── Đảm bảo các field bắt buộc ──
testCases.forEach(tc => {
  if (!tc.endpointId) throw new Error('TestCase thiếu endpointId trong LLM response.');
  tc.testType = tc.testType ?? 'HappyPath';
  tc.priority = tc.priority ?? 'Medium';
  if (!tc.request) tc.request = { httpMethod: 'GET', url: '/', bodyType: 'None', timeout: 30000 };
  if (!tc.expectation) tc.expectation = { expectedStatus: '[200]' };
});

// ── Đọc callbackUrl & callbackApiKey từ node Parse Input ──
const inputNode = $('Parse Input').first().json;
const callbackUrl = inputNode.callbackUrl ?? '';
const callbackApiKey = inputNode.callbackApiKey ?? '';

if (!callbackUrl || !callbackUrl.startsWith('http')) {
  throw new Error('callbackUrl rỗng hoặc không hợp lệ: "' + callbackUrl + '". Hãy kiểm tra BeBaseUrl trong appsettings.json của BE.');
}

return [{
  json: {
    testCases,
    callbackUrl,
    callbackApiKey
  }
}];
